contracts/ShadowLensAgentConsumer.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title Ritual-native ShadowLens analysis contract
/// @notice Supports Ritual precompile-based analysis, X API / HTTP calls, and weekly monitoring metadata.
contract ShadowLensAgentConsumer {
    address public constant SOVEREIGN_AGENT = address(0x080C);
    address public constant HTTP_PRECOMPILE = address(0x0801);
    address public constant ASYNC_DELIVERY = 0x5A16214fF555848411544b005f7Ac063742f39F6;

    address public owner;

    enum Status {
        Pending,
        Completed
    }

    enum RiskLevel {
        Unknown,
        Low,
        Medium,
        High
    }

    struct Analysis {
        bytes32 requestId;
        address requester;
        string handle;
        RiskLevel riskLevel;
        string engagementHealth;
        string postingPattern;
        string contentRisk;
        string suggestedFixes;
        bool weeklyMonitor;
        Status status;
        uint256 createdAt;
        uint256 updatedAt;
    }

    mapping(bytes32 => Analysis) public analyses;
    mapping(address => bool) public authorizedOracles;
    mapping(bytes32 => uint256) public monitorCadenceSeconds;

    event AnalysisRequested(bytes32 indexed requestId, address indexed requester, string handle, bool weeklyMonitor);
    event AnalysisCompleted(
        bytes32 indexed requestId,
        RiskLevel riskLevel,
        string engagementHealth,
        string postingPattern,
        string contentRisk,
        string suggestedFixes
    );
    event PrecompileSubmitted(address indexed precompile, bytes input, bytes output);
    event WeeklyMonitorScheduled(bytes32 indexed requestId, uint256 cadenceSeconds);
    event OracleUpdated(address indexed oracle, bool enabled);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyOracle() {
        require(authorizedOracles[msg.sender], "Not authorized oracle");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function setOracle(address oracle, bool enabled) external onlyOwner {
        authorizedOracles[oracle] = enabled;
        emit OracleUpdated(oracle, enabled);
    }

    /// @notice Request ShadowLens analysis via the Ritual sovereign agent precompile.
    /// @param precompileInput Encoded input for the sovereign agent or HTTP/X API workflow.
    /// @param handle The user handle or X profile identifier to analyze.
    /// @param weeklyMonitor If true, the request should be included in weekly monitoring workflows.
    function requestAnalysisWithAgent(
        bytes calldata precompileInput,
        string calldata handle,
        bool weeklyMonitor
    ) external returns (bytes memory) {
        bytes32 requestId = keccak256(abi.encodePacked(msg.sender, handle, block.timestamp));

        analyses[requestId] = Analysis({
            requestId: requestId,
            requester: msg.sender,
            handle: handle,
            riskLevel: RiskLevel.Unknown,
            engagementHealth: "",
            postingPattern: "",
            contentRisk: "",
            suggestedFixes: "",
            weeklyMonitor: weeklyMonitor,
            status: Status.Pending,
            createdAt: block.timestamp,
            updatedAt: block.timestamp
        });

        emit AnalysisRequested(requestId, msg.sender, handle, weeklyMonitor);

        (bool ok, bytes memory output) = SOVEREIGN_AGENT.call(precompileInput);
        require(ok, "Sovereign agent call failed");

        emit PrecompileSubmitted(SOVEREIGN_AGENT, precompileInput, output);
        return output;
    }

    /// @notice Request ShadowLens analysis via Ritual HTTP precompile (for X API access).
    /// @param httpInput Encoded `HTTPCallRequest` payload for the X API endpoint.
    /// @param handle The user handle or X profile identifier to analyze.
    /// @param weeklyMonitor If true, this request should be evaluated as part of weekly monitoring.
    function requestAnalysisWithHttp(
        bytes calldata httpInput,
        string calldata handle,
        bool weeklyMonitor
    ) external returns (bytes memory) {
        bytes32 requestId = keccak256(abi.encodePacked(msg.sender, handle, block.timestamp));

        analyses[requestId] = Analysis({
            requestId: requestId,
            requester: msg.sender,
            handle: handle,
            riskLevel: RiskLevel.Unknown,
            engagementHealth: "",
            postingPattern: "",
            contentRisk: "",
            suggestedFixes: string(httpInput),
            weeklyMonitor: weeklyMonitor,
            status: Status.Pending,
            createdAt: block.timestamp,
            updatedAt: block.timestamp
        });

        emit AnalysisRequested(requestId, msg.sender, handle, weeklyMonitor);

        (bool ok, bytes memory output) = HTTP_PRECOMPILE.call(httpInput);
        require(ok, "HTTP precompile call failed");

        analyses[requestId].status = Status.Completed;
        analyses[requestId].updatedAt = block.timestamp;
        analyses[requestId].suggestedFixes = string(output);

        emit PrecompileSubmitted(HTTP_PRECOMPILE, httpInput, output);
        emit AnalysisCompleted(requestId, RiskLevel.Unknown, "", "", "", string(output));
        return output;
    }

    /// @notice Handle the async callback from Ritual's AsyncDelivery contract.
    /// @param jobId The original request ID.
    /// @param result An opaque payload containing the analysis result.
    function onSovereignAgentResult(bytes32 jobId, bytes calldata result) external {
        require(msg.sender == ASYNC_DELIVERY, "unauthorized callback sender");
        Analysis storage analysis = analyses[jobId];
        require(analysis.requester != address(0), "unknown jobId");
        require(analysis.status == Status.Pending, "job already completed");

        analysis.status = Status.Completed;
        analysis.updatedAt = block.timestamp;
        analysis.suggestedFixes = string(result);

        emit AnalysisCompleted(
            jobId,
            analysis.riskLevel,
            analysis.engagementHealth,
            analysis.postingPattern,
            analysis.contentRisk,
            analysis.suggestedFixes
        );
    }

    function fulfillAnalysis(
        bytes32 requestId,
        RiskLevel riskLevel,
        string calldata engagementHealth,
        string calldata postingPattern,
        string calldata contentRisk,
        string calldata suggestedFixes
    ) external onlyOracle {
        Analysis storage analysis = analyses[requestId];
        require(analysis.requester != address(0), "unknown requestId");
        require(analysis.status == Status.Pending, "already completed");

        analysis.riskLevel = riskLevel;
        analysis.engagementHealth = engagementHealth;
        analysis.postingPattern = postingPattern;
        analysis.contentRisk = contentRisk;
        analysis.suggestedFixes = suggestedFixes;
        analysis.status = Status.Completed;
        analysis.updatedAt = block.timestamp;

        emit AnalysisCompleted(requestId, riskLevel, engagementHealth, postingPattern, contentRisk, suggestedFixes);
    }

    function scheduleWeeklyMonitor(bytes32 requestId, uint256 cadenceSeconds) external {
        Analysis storage analysis = analyses[requestId];
        require(analysis.requester == msg.sender || msg.sender == owner, "unauthorized");
        require(cadenceSeconds > 0, "cadence must be positive");

        monitorCadenceSeconds[requestId] = cadenceSeconds;
        emit WeeklyMonitorScheduled(requestId, cadenceSeconds);
    }
}

contracts/ShadowLensProtocol.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ShadowLensProtocol {

    struct Analysis {
        bytes32 requestId;
        address requester;
        string handle;
        uint256 score;
        string reason;
        bool fulfilled;
    }

    mapping(bytes32 => Analysis) public analyses;

    address public immutable oracle;
    uint256 public requestCount;

    event AnalysisRequested(
        bytes32 indexed requestId,
        address indexed requester,
        string handle
    );

    event AnalysisFulfilled(
        bytes32 indexed requestId,
        uint256 score,
        string reason
    );

    constructor(address _oracle) {
        oracle = _oracle;
        requestCount = 0;
    }

    function requestAnalysis(string calldata handle) external {
        requestCount++;
        bytes32 requestId = keccak256(
            abi.encodePacked(msg.sender, handle, block.timestamp, requestCount)
        );

        analyses[requestId] = Analysis({
            requestId: requestId,
            requester: msg.sender,
            handle: handle,
            score: 0,
            reason: "",
            fulfilled: false
        });

        emit AnalysisRequested(requestId, msg.sender, handle);
    }

    function fulfillAnalysis(
        bytes32 requestId,
        uint256 score,
        string calldata reason
    ) external {
        require(msg.sender == oracle, "Only oracle can fulfill");
        require(!analyses[requestId].fulfilled, "Already fulfilled");

        Analysis storage a = analyses[requestId];
        a.score = score;
        a.reason = reason;
        a.fulfilled = true;

        emit AnalysisFulfilled(requestId, score, reason);
    }

    function getAnalysis(bytes32 requestId)
        external
        view
        returns (Analysis memory)
    {
        return analyses[requestId];
    }
}

